const inputData = $input.item.json;
const batchRecord = $('Prepare Batch1').item.json.llm_batch_record;
const payload = $('Prepare Batch1').item.json.llm_payload;

let llmCallResult;
if (Array.isArray(inputData)) {
    llmCallResult = inputData[0] || {};
} else {
    llmCallResult = inputData;
}

if (typeof llmCallResult !== 'object' || llmCallResult === null) {
    llmCallResult = {error: true, message: "Invalid response type"};
}

const hasError = llmCallResult.error !== undefined;
console.log(`🔍 Result: error=${hasError}`);

return [{
    json: {
        ...llmCallResult,
        batch_data: batchRecord,
        payload: payload
    }
}];

// RETRY LOGIC - Split batch into smaller pieces
const preservedData = $json;
const batchData = preservedData.batch_data;
const payload = preservedData.payload;

if (!batchData || !payload || !payload.articles) {
  return [{
    json: {
      error: true,
      message: "Missing data for retry",
      skipped: true
    }
  }];
}

const originalArticles = payload.articles;
const retryCount = batchData.retry_count || 0;
const currentSize = batchData.current_batch_size;

console.log(`❌ TIMEOUT: Batch failed with ${currentSize} articles. Retry count: ${retryCount}`);

if (retryCount >= 3) {
  console.log(`⚠️ Max retries reached.`);
  return [{
    json: {
      error: true,
      error_type: "max_retry_exceeded",
      message: "Max retries reached",
      request_id: batchData.request_id,
      skipped: true
    }
  }];
}

const newBatchSize = Math.max(5, Math.floor(currentSize / 2));
console.log(`🔄 Splitting batch: ${currentSize} → ${newBatchSize} articles`);

const subBatches = [];
for (let i = 0; i < originalArticles.length; i += newBatchSize) {
  subBatches.push(originalArticles.slice(i, i + newBatchSize));
}

console.log(`📦 Created ${subBatches.length} sub-batches`);

return subBatches.map((articles, idx) => {
  const subRequestId = `${batchData.request_id}_retry${retryCount + 1}_sub${idx + 1}`;

  return {
    json: {
      llm_payload: {
        request_id: subRequestId,
        articles: articles,
        similarity_threshold: payload.similarity_threshold || 0.7,
        use_existing_clusters: payload.use_existing_clusters !== false,
        min_cluster_size: payload.min_cluster_size || 2
      },
      llm_batch_record: {
        request_id: subRequestId,
        parent_request_id: batchData.parent_request_id || batchData.request_id,
        filters_used: batchData.filters_used,
        options: batchData.options,
        article_ids: articles.map(a => a.id).filter(Boolean),
        article_count: articles.length,
        status: "pending_retry",
        ingested_at: new Date().toISOString(),
        trigger_type: "incremental_retry",
        llm_endpoint: "/cluster_create",
        retry_count: retryCount + 1,
        current_batch_size: articles.length,
        original_batch_size: currentSize
      }
    }
  };
});

const filters = {
  time_window: null,
  category: null,
  keywords: [],
  size: 1000
};
const options = {
  style_version: "Neutral",
  sentiment_target: "None",
  similarity_threshold: 0.7,
  use_existing_clusters: true,
  min_cluster_size: 2,
  model: "gpt-4o-mini"
};

// Get clustered article IDs from the previous node
const clusteredIds = $('Extract IDs').first().json.clustered_article_ids || [];

// Build query to exclude clustered articles
const query = {
  bool: {
    must: {
      match_all: {}
    },
    must_not: {
      terms: {
        id: clusteredIds
      }
    }
  }
};

return [{ json: {
  filters,
  options,
  opensearch_query: {
    size: filters.size,
    _source: ['id', 'title', 'body', 'source', 'published_at', 'url', 'language'],
    query,
    sort: [{ published_at: { order: 'desc' }}]
  }
}}];

const hits = $json.hits?.hits ?? [];
const articles = hits.map(h => h._source).filter(a => a && a.body);
const processed = articles.map(a => ({...a, body_truncated: false}));
console.log(`📊 Processing ${processed.length} articles`);
return processed.map(a => ({ json: a }));

const items = $input.all().map(i => i.json);
const pad2 = n => String(n).padStart(2, '0');
const pad3 = n => String(n).padStart(3, '0');
const now = new Date();
const datePart = `${now.getFullYear()}-${pad2(now.getMonth()+1)}-${pad2(now.getDate())}_${pad2(now.getHours())}${pad2(now.getMinutes())}`;
const requestId = `n8n_incr_${datePart}_${pad3($runIndex+1)}`;
const filterData = $('Build OpenSearch Query1').first().json;
const filters = filterData?.filters || {};
const options = filterData?.options || {};
const articleIds = items.map(a => a.id).filter(Boolean);
const articles = items.map(a => ({
  id: a.id || "",
  url: a.url || "",
  title: a.title || "",
  body: a.body || "",
  language: a.language || "en",
  source: a.source || "",
  published_at: a.published_at || null,
  category: "general"
}));
if (articles.length > 100) throw new Error(`Too many: ${articles.length}`);
if (articles.length === 0) throw new Error('No articles');
console.log(`✅ BATCH ${$runIndex + 1}: ${articles.length} articles`);
return [{
  json: {
    llm_payload: {
      request_id: requestId,
      articles: articles,
      similarity_threshold: options.similarity_threshold || 0.7,
      use_existing_clusters: options.use_existing_clusters !== true,
      min_cluster_size: options.min_cluster_size || 2
    },
    llm_batch_record: {
      request_id: requestId,
      filters_used: filters,
      options: options,
      article_ids: articleIds,
      article_count: articles.length,
      status: "pending",
      ingested_at: new Date().toISOString(),
      trigger_type: "incremental",
      llm_endpoint: "/cluster_create",
      retry_count: 0,
      current_batch_size: articles.length
    }
  }
}];

// This node should have TWO inputs: one from summaries, one from clusters
const allInputs = $input.all();

console.log(`🔄 Merging results from ${allInputs.length} branches`);

let summariesCount = 0;
let clustersCount = 0;

allInputs.forEach(input => {
  if (input.json.branch === 'summaries') {
    summariesCount = input.json.summaries_count || 0;
  } else if (input.json.branch === 'clusters') {
    clustersCount = input.json.clusters_count || 0;
  }
});

console.log(`📊 Final counts: ${summariesCount} summaries, ${clustersCount} clusters`);

// Get the original batch record
const batchRecord = $('Prepare Batch1').first().json.llm_batch_record;

return [{
  json: {
    request_id: batchRecord.request_id,
    update_doc: {
      status: "completed",
      completed_at: new Date().toISOString(),
      article_summaries_count: summariesCount,
      clusters_count: clustersCount
    }
  }
}];

const hits = $json.hits?.hits || [];
const clusteredIds = new Set();

hits.forEach(hit => {
  const ids = hit._source?.article_ids || [];
  ids.forEach(id => clusteredIds.add(id));
});

return [{
  json: {
    clustered_article_ids: Array.from(clusteredIds)
  }
}];

// Wait for all cluster inserts to complete
const allResults = $input.all();

console.log(`✅ Inserted ${allResults.length} clusters`);

const successful = allResults.filter(r => r.json.result === 'created' || r.json.result === 'updated').length;

return [{
  json: {
    branch: 'clusters',
    clusters_count: successful,
    clusters_processed: allResults.length
  }
}];

// Split clusters into individual items for KNN processing
const inputData = $input.all();
const outputItems = [];

for (const item of inputData) {
  const data = item.json;

  // Check if this is cluster data with clusters array
  if (data.clusters && Array.isArray(data.clusters)) {
    const requestId = data.request_id;

    // Create one item per cluster
    for (const cluster of data.clusters) {
      // Validate centroid_embedding
      let centroidEmbedding = cluster.centroid_embedding || [];

      if (centroidEmbedding.length < 384) {
        console.log(`⚠️  Cluster ${cluster.cluster_id}: Padding ${centroidEmbedding.length} → 384`);
        centroidEmbedding = [
          ...centroidEmbedding,
          ...Array(384 - centroidEmbedding.length).fill(0.0)
        ];
      } else if (centroidEmbedding.length > 384) {
        console.log(`⚠️  Cluster ${cluster.cluster_id}: Truncating ${centroidEmbedding.length} → 384`);
        centroidEmbedding = centroidEmbedding.slice(0, 384);
      }

      outputItems.push({
        json: {
          original_cluster: cluster,
          centroid_embedding: centroidEmbedding,
          _request_id: requestId
        },
        pairedItem: { item: inputData.indexOf(item) }
      });
    }
  }
}

console.log(`📊 Split into ${outputItems.length} clusters for individual KNN processing`);
return outputItems;

const knnResult = $json;

// Get data from Process Response2 node
const processNode = $('Process Response2').item.json;
const originalCluster = processNode.original_cluster;
const centroidEmbedding = processNode.centroid_embedding;
const requestId = processNode._request_id;

const hits = knnResult.hits?.hits || [];
const totalMatches = knnResult.hits?.total?.value || 0;

console.log(`🔍 Cluster ${originalCluster.cluster_id}: Found ${totalMatches} potential matches`);

// Filter out inactive clusters and those with 0 articles
const validHits = hits.filter(hit => {
  const status = hit._source?.status;
  const articleCount = hit._source?.article_count || 0;
  return status === 'active' && articleCount >= 1;
});

console.log(`✅ Valid matches after filtering: ${validHits.length}/${hits.length}`);

let action = 'create';
let targetClusterId = null;
let similarityScore = 0;
let existingCluster = null;

if (validHits.length > 0) {
  const topMatch = validHits[0];
  similarityScore = topMatch._score || 0;

  console.log(`📊 Top match score: ${similarityScore.toFixed(4)} (threshold: 0.75)`);

  if (similarityScore >= 0.75) {
    action = 'merge';
    targetClusterId = topMatch._id;
    existingCluster = topMatch._source;
    console.log(`✅ MERGE: Similarity ${similarityScore.toFixed(4)} >= 0.75, merging with cluster ${targetClusterId}`);
  } else {
    console.log(`➕ CREATE: Similarity ${similarityScore.toFixed(4)} < 0.75, creating new cluster`);
  }
} else {
  console.log(`➕ CREATE: No valid similar clusters found, creating new cluster`);
}

return [{
  json: {
    action: action,
    original_cluster: originalCluster,
    centroid_embedding: centroidEmbedding,
    target_cluster_id: targetClusterId,
    existing_cluster: existingCluster,
    similarity_score: similarityScore,
    knn_matches: validHits.length,
    total_matches: hits.length,
    _request_id: requestId
  }
}];

const decision = $json;
const newCluster = decision.original_cluster;
const centroidEmbedding = decision.centroid_embedding;

const now = new Date().toISOString();
const docId = decision._request_id 
  ? `${decision._request_id}_${newCluster.cluster_id}` 
  : `cluster_${newCluster.cluster_id}_${Date.now()}`;

const clusterDoc = {
  _id: docId,
  body: {
    cluster_id: String(newCluster.cluster_id),
    article_ids: newCluster.article_ids || [],
    article_count: newCluster.article_count || 0,
    centroid_embedding: centroidEmbedding,
    status: "active",
    created_at: now,
    last_updated_at: now,
    ingested_at: now,
    processed_at: now
  }
};

console.log(`➕ CREATE: New cluster ${newCluster.cluster_id} with ${newCluster.article_count} articles`);

return [{ json: clusterDoc }];

const decision = $json;
const existing = decision.existing_cluster;
const newCluster = decision.original_cluster;

// Merge article IDs (remove duplicates)
const mergedArticleIds = [...new Set([
  ...(existing.article_ids || []),
  ...(newCluster.article_ids || [])
])];

// Calculate new centroid (average of embeddings)
const existingEmbedding = existing.centroid_embedding || [];
const newEmbedding = decision.centroid_embedding || [];

const mergedEmbedding = existingEmbedding.map((val, idx) => {
  return (val + (newEmbedding[idx] || 0)) / 2;
});

const now = new Date().toISOString();

const mergedCluster = {
  _id: decision.target_cluster_id,
  body: {
    cluster_id: existing.cluster_id,
    article_ids: mergedArticleIds,
    article_count: mergedArticleIds.length,
    centroid_embedding: mergedEmbedding,
    status: "active",
    created_at: existing.created_at || now,
    last_updated_at: now,
    ingested_at: existing.ingested_at || now,
    processed_at: now
  }
};

console.log(`🔀 MERGE: ${existing.article_ids?.length || 0} + ${newCluster.article_ids?.length || 0} = ${mergedArticleIds.length} articles`);
console.log(`📊 Similarity: ${decision.similarity_score.toFixed(4)}`);

return [{ json: mergedCluster }];

// Wait for all summary inserts to complete
const allResults = $input.all();

console.log(`✅ Inserted ${allResults.length} article summaries`);

const successful = allResults.filter(r => r.json.result === 'created' || r.json.result === 'updated').length;

return [{
  json: {
    branch: 'summaries',
    summaries_count: successful,
    summaries_processed: allResults.length
  }
}];

const data = $json;
const articleSummaries = data.article_summaries;

// If no article_summaries, skip this branch
if (!articleSummaries || typeof articleSummaries !== 'object' || Object.keys(articleSummaries).length === 0) {
  console.log('⏭️  No article summaries to process, skipping');
  return [];
}

console.log(`Preparing ${Object.keys(articleSummaries).length} summaries individually`);

// Convert object to array of items
const summaryItems = [];
for (const [articleId, summary] of Object.entries(articleSummaries)) {
  summaryItems.push({
    json: {
      _id: `${articleId}_summary`,
      document: {
        id: `${articleId}_summary`,
        article_id: articleId,
        summary: summary,
        language: data.language || 'en',
        model: data.model || 'gpt-4o-mini',
        style_version: data.style_version || 'Neutral',
        sentiment: data.sentiment || 'None',
        processed_at: data.processed_at || new Date().toISOString()
      }
    }
  });
}

return summaryItems;
